/* ===== Inmo Studio PRO 2.1: flujo Lavinia y control avanzado ===== */
(function(){
  let projectTitle='Proyecto Lavinia';
  const projectNameEl=document.getElementById('projectName');
  const pageNameEl=document.getElementById('pageName');
  const exportLayersBtn=document.getElementById('exportLayersBtn');

  function safeName(value,fallback='pieza'){
    const s=String(value||fallback).trim().replace(/[\\/:*?"<>|]+/g,'-').replace(/\s+/g,'-');
    return s || fallback;
  }
  function ensureSlideMeta(){
    slidesData.forEach((s,i)=>{if(!s.name)s.name=String(i+1)});
  }
  function updateNaming(){
    ensureSlideMeta();
    if(projectNameEl)projectNameEl.value=projectTitle;
    if(pageNameEl)pageNameEl.value=current()?.name||String(currentSlide+1);
  }
  if(projectNameEl)projectNameEl.oninput=e=>projectTitle=e.target.value;
  if(pageNameEl)pageNameEl.oninput=e=>{if(current()){current().name=e.target.value||String(currentSlide+1)}};

  // Recupera exactamente el ornamento geométrico original de Lavinia.
  const previousDrawLayer=drawLayer;
  drawLayer=function(l){
    if(l.type!=='ornament') return previousDrawLayer(l);
    if(!l.visible)return;
    ctx.save();ctx.globalAlpha=l.opacity??.7;ctx.translate(l.x,l.y);
    ctx.strokeStyle=l.stroke||'#68c9c0';ctx.lineWidth=Math.max(2,4*(l.w/218));ctx.lineCap='butt';ctx.lineJoin='miter';
    const sx=l.w/218,sy=l.h/220;ctx.scale(sx,sy);
    ctx.beginPath();
    ctx.moveTo(0,0);ctx.lineTo(163,0);ctx.lineTo(163,24);ctx.quadraticCurveTo(163,48,188,48);ctx.lineTo(218,48);ctx.lineTo(218,218);
    ctx.moveTo(0,21);ctx.lineTo(193,21);ctx.lineTo(193,220);ctx.stroke();
    ctx.restore();
  };

  // Mejora las plantillas Lavinia sin alterar la composición base.
  const previousTemplate=template;
  template=function(name){
    if(client==='lavinia'&&name==='Imagen de fondo'){
      const s=blankSlide();s.name=String(currentSlide+1);s.background='#ffffff';
      s.layers=[imageLayer(null,{x:0,y:0,w:1080,h:1350,name:'Imagen de fondo'})];
      return s;
    }
    const s=previousTemplate(name);s.name=s.name||String(currentSlide+1);
    if(client==='lavinia'&&(name==='Tip inmobiliario'||name==='Frase profesional')){
      const label=s.layers.find(l=>l.type==='text'&&(l.text==='TIP'||l.text==='FRASE'));
      if(label){
        label.fill='#ffffff';label.x=82;label.y=818;label.w=245;label.h=62;label.fontSize=27;label.align='center';label.name='Texto etiqueta';
        const idx=s.layers.indexOf(label);
        s.layers.splice(idx,0,shapeLayer({x:70,y:805,w:270,h:72,fill:'#68c9c0',radius:36,name:'Fondo verde TIP',locked:true,master:true}));
      }
    }
    return s;
  };
  if(!clients.lavinia.templates.includes('Imagen de fondo'))clients.lavinia.templates.push('Imagen de fondo');

  // Editor de texto realmente sobre la plantilla. Enter crea saltos de línea.
  function openInlineText(l){
    document.querySelector('.inline-text-editor')?.remove();
    const ta=document.createElement('textarea');ta.className='inline-text-editor';ta.value=l.text||'';
    ta.style.left=l.x+'px';ta.style.top=l.y+'px';ta.style.width=l.w+'px';ta.style.height=Math.max(l.h,90)+'px';
    ta.style.fontFamily=l.fontFamily||'Arial';ta.style.fontSize=(l.fontSize||40)+'px';ta.style.fontWeight=l.fontWeight||700;ta.style.textAlign=l.align||'left';
    canvasShell.appendChild(ta);ta.focus();ta.select();
    let saved=false;
    const commit=()=>{if(saved)return;saved=true;pushHistory();l.text=ta.value;l.name=(ta.value.split('\n')[0]||'Texto').slice(0,24);ta.remove();renderAll()};
    ta.addEventListener('input',()=>{l.text=ta.value;renderCanvas()});
    ta.addEventListener('keydown',e=>{if(e.key==='Escape'){e.preventDefault();ta.remove();renderAll()}if((e.ctrlKey||e.metaKey)&&e.key==='Enter'){e.preventDefault();commit()}});
    ta.addEventListener('blur',commit);
  }
  canvas.ondblclick=e=>{
    const p=localPos(e),l=hit(p.x,p.y);if(!l)return;selected=l.id;
    if(l.type==='text')openInlineText(l);else if(l.type==='image')imageUpload.click();
  };

  // Capas: eliminar visible, subir/bajar y arrastrar para reordenar.
  renderLayers=function(){
    layers.innerHTML='';
    [...current().layers].reverse().forEach(l=>{
      const r=document.createElement('div');r.className='layer-row'+(l.id===selected?' active':'')+(l.master?' master':'');r.draggable=true;r.dataset.id=l.id;
      r.innerHTML=`<button class="eye" title="Mostrar u ocultar">${l.visible?'◉':'○'}</button><div class="layer-name">${l.name}</div>${l.master?'<span class="master-tag">MASTER</span>':'<span></span>'}<div class="layer-actions"><button class="layer-mini up" title="Subir">↑</button><button class="layer-mini down" title="Bajar">↓</button><button class="layer-mini remove" title="Eliminar">×</button><button class="lock" title="Bloquear">${l.locked?'🔒':'·'}</button></div>`;
      r.onclick=e=>{
        if(e.target.classList.contains('eye')){l.visible=!l.visible;renderAll();return}
        if(e.target.classList.contains('remove')){if(l.master&&l.locked){toast('Desactiva Proteger plantilla para eliminar esta capa MASTER');return}selected=l.id;act('delete');return}
        if(e.target.classList.contains('up')){selected=l.id;act('front');return}
        if(e.target.classList.contains('down')){selected=l.id;act('back');return}
        if(e.target.classList.contains('lock')){l.locked=!l.locked;renderAll();return}
        selected=l.id;renderAll();
      };
      r.ondragstart=()=>r.classList.add('dragging');r.ondragend=()=>r.classList.remove('dragging');
      r.ondragover=e=>{e.preventDefault();r.classList.add('drag-over')};r.ondragleave=()=>r.classList.remove('drag-over');
      r.ondrop=e=>{e.preventDefault();r.classList.remove('drag-over');const fromId=document.querySelector('.layer-row.dragging')?.dataset.id;if(!fromId||fromId===l.id)return;pushHistory();const arr=current().layers,from=arr.findIndex(x=>x.id===fromId),to=arr.findIndex(x=>x.id===l.id);const [m]=arr.splice(from,1);arr.splice(to,0,m);renderAll()};
      layers.appendChild(r);
    });
  };

  // Páginas con nombre y botón de eliminación explícito.
  renderSlides=function(){
    ensureSlideMeta();const box=document.getElementById('slides');box.querySelectorAll('.slide-wrap,.slide').forEach(n=>n.remove());
    slidesData.forEach((s,i)=>{
      const wrap=document.createElement('div');wrap.className='slide-wrap';
      const b=document.createElement('button');b.className='slide'+(i===currentSlide?' active':'');b.innerHTML=`<span>${i+1}</span><small>${String(s.name||i+1).slice(0,8)}</small>`;
      b.onclick=()=>{currentSlide=i;selected=null;renderAll();updateNaming()};wrap.appendChild(b);
      if(slidesData.length>1){const del=document.createElement('button');del.className='slide-delete';del.textContent='×';del.title='Eliminar página';del.onclick=e=>{e.stopPropagation();pushHistory();slidesData.splice(i,1);currentSlide=Math.min(currentSlide,slidesData.length-1);selected=null;renderAll();updateNaming()};wrap.appendChild(del)}
      box.insertBefore(wrap,document.getElementById('addSlide'));
    });
  };

  // Exportación JPG usando exactamente el nombre de la pieza: 25.jpg, portada.jpg, etc.
  exportJpg=function(){
    const oldSel=selected;selected=null;renderCanvas();
    const out=document.createElement('canvas');out.width=W;out.height=H;out.getContext('2d').drawImage(canvas,0,0);
    selected=oldSel;renderCanvas();const a=document.createElement('a');a.download=safeName(current().name,String(currentSlide+1))+'.jpg';a.href=out.toDataURL('image/jpeg',.96);a.click();toast('JPG exportado: '+a.download);
  };
  exportBtn.onclick=exportJpg;

  // Canva/CapCut: cada capa se exporta al tamaño completo en PNG transparente.
  async function exportLayers(){
    const arr=current().layers,states=arr.map(l=>l.visible),oldSel=selected,oldBg=current().background;selected=null;current().background='rgba(0,0,0,0)';
    for(let i=0;i<arr.length;i++){
      arr.forEach((l,j)=>l.visible=j===i&&states[j]);renderCanvas();
      const out=document.createElement('canvas');out.width=W;out.height=H;out.getContext('2d').drawImage(canvas,0,0);
      const a=document.createElement('a');a.download=`${String(i+1).padStart(2,'0')}-${safeName(arr[i].name,'capa')}.png`;a.href=out.toDataURL('image/png');a.click();
      await new Promise(r=>setTimeout(r,170));
    }
    arr.forEach((l,i)=>l.visible=states[i]);current().background=oldBg;selected=oldSel;renderAll();toast('Capas PNG transparentes exportadas');
  }
  exportLayersBtn.onclick=exportLayers;

  // Guardado con nombre de proyecto y nombres por página.
  save=function(){
    ensureSlideMeta();const data={version:3,client,projectTitle,slides:slidesData};const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([JSON.stringify(data)],{type:'application/json'}));a.download=safeName(projectTitle,'proyecto')+'.json';a.click();toast('Proyecto guardado');
  };
  saveProject.onclick=save;
  const oldOpenFile=openFile;
  openFile=function(f){const r=new FileReader();r.onload=()=>{try{const d=JSON.parse(r.result);projectTitle=d.projectTitle||'Proyecto';if(d.client&&clients[d.client]){client=d.client;document.documentElement.style.setProperty('--accent',clients[client].accent);brandTitle.textContent=clients[client].name+' Studio';buildTemplates()}slidesData=d.slides||[blankSlide()];currentSlide=0;selected=null;renderAll();updateNaming();toast('Proyecto abierto')}catch(e){alert('El archivo no es válido')}};r.readAsText(f)};
  projectFile.onchange=e=>e.target.files[0]&&openFile(e.target.files[0]);

  // Añadir página toma una plantilla vacía con imagen de fondo, no un lienzo incomprensible.
  addSlide.onclick=()=>{pushHistory();const s=client==='lavinia'?template('Imagen de fondo'):blankSlide();s.name=String(slidesData.length+1);slidesData.push(s);currentSlide=slidesData.length-1;selected=null;renderAll();updateNaming()};

  const oldRenderAll2=renderAll;
  renderAll=function(){oldRenderAll2();updateNaming()};
  const oldSetClient2=setClient;
  setClient=function(c){oldSetClient2(c);projectTitle='Proyecto '+clients[c].name;updateNaming()};
  const oldNewDoc2=newDoc;
  newDoc=function(){oldNewDoc2();projectTitle='Proyecto '+clients[client].name;ensureSlideMeta();updateNaming()};

  // Botón claro para encontrar la protección de plantilla.
  const observer=new MutationObserver(()=>{
    const btn=document.getElementById('protectTemplate');if(btn&&!btn.dataset.labeled){btn.dataset.labeled='1';btn.title='Activa o desactiva el bloqueo de elementos maestros';const card=btn.closest('.control-card');if(card&&!card.querySelector('.export-hint')){const h=document.createElement('div');h.className='export-hint';h.textContent='Aquí se desactiva la protección para poder mover o borrar elementos MASTER.';card.appendChild(h)}}
  });
  const brand=document.getElementById('brandControls');if(brand)observer.observe(brand,{childList:true,subtree:true});
  newProject.onclick=newDoc;
  updateNaming();
})();


/* ===== Inmo Studio PRO 2.4: editor de plantilla base ===== */
(function(){
  const openBtn=document.getElementById('editMasterBtn');
  const modal=document.getElementById('masterEditorModal');
  const list=document.getElementById('masterLayerList');
  const closeBtn=document.getElementById('closeMasterEditor');
  const doneBtn=document.getElementById('doneMasterEditor');
  const unlockAll=document.getElementById('unlockAllMasters');
  const lockAll=document.getElementById('lockAllMasters');
  const resetLogo=document.getElementById('resetLaviniaLogo');

  function masters(){ return current().layers.filter(l=>l.master); }
  function iconFor(l){
    if(l.name==='Logo Lavinia') return 'L';
    if(l.type==='ornament') return '⌁';
    if(l.type==='gradient') return '◐';
    if(l.type==='shape') return '□';
    if(l.type==='image') return '▧';
    return 'T';
  }
  function selectMaster(l){ selected=l.id; renderAll(); modal.classList.add('hidden'); toast('Capa seleccionada: '+l.name); }
  function renderMasterList(){
    if(!list)return;
    list.innerHTML='';
    const items=masters();
    if(!items.length){list.innerHTML='<div class="master-empty">Esta página no tiene capas MASTER.</div>';return;}
    items.slice().reverse().forEach(l=>{
      const row=document.createElement('div');
      row.className='master-item'+(l.locked?' locked':' unlocked');
      row.innerHTML=`<div class="master-icon">${iconFor(l)}</div><div class="master-info"><b>${l.name}</b><small>${l.locked?'Bloqueada':'Editable en el lienzo'}</small></div><button class="master-select">Seleccionar</button><button class="master-toggle ${l.locked?'':'active'}">${l.locked?'Desbloquear':'Bloquear'}</button>`;
      row.querySelector('.master-select').onclick=()=>selectMaster(l);
      row.querySelector('.master-toggle').onclick=()=>{
        pushHistory();
        l.locked=!l.locked;
        if(!l.locked) templateProtected=false;
        renderAll(); renderMasterList(); syncBrandControls();
      };
      list.appendChild(row);
    });
  }
  function open(){
    renderMasterList();
    modal.classList.remove('hidden');
  }
  function close(){modal.classList.add('hidden')}
  if(openBtn)openBtn.onclick=open;
  if(closeBtn)closeBtn.onclick=close;
  if(doneBtn)doneBtn.onclick=close;
  if(modal)modal.onclick=e=>{if(e.target===modal)close()};
  document.addEventListener('keydown',e=>{if(e.key==='Escape'&&modal&&!modal.classList.contains('hidden'))close()});
  if(unlockAll)unlockAll.onclick=()=>{pushHistory();templateProtected=false;masters().forEach(l=>l.locked=false);renderAll();renderMasterList();syncBrandControls();toast('Capas MASTER desbloqueadas')};
  if(lockAll)lockAll.onclick=()=>{pushHistory();templateProtected=true;masters().forEach(l=>l.locked=true);renderAll();renderMasterList();syncBrandControls();toast('Plantilla base protegida')};
  if(resetLogo)resetLogo.onclick=()=>{
    const logo=logoCurrent();
    if(!logo){toast('No hay logo Lavinia en esta página');return;}
    pushHistory();
    logo.x=70;
    logo.y=(activeTemplate==='Propiedad')?1140:45;
    logo.w=(activeTemplate==='Propiedad')?240:260;
    logo.h=(activeTemplate==='Propiedad')?135:145;
    logo.locked=false;
    templateProtected=false;
    selected=logo.id;
    renderAll();renderMasterList();syncBrandControls();
    toast('Logo ubicado a la izquierda y desbloqueado');
  };

  // Acceso individual desde el inspector para cualquier capa MASTER.
  const previousRenderInspector=renderInspector;
  renderInspector=function(){
    previousRenderInspector();
    const l=findLayer(selected),el=document.getElementById('inspector');
    if(!l||!l.master||!el)return;
    const card=document.createElement('div');card.className='master-inspector-card';
    card.innerHTML=`<div><b>Plantilla base</b><small>${l.locked?'Esta capa está protegida':'Esta capa se puede mover y redimensionar'}</small></div><button id="toggleSelectedMaster">${l.locked?'Desbloquear capa':'Bloquear capa'}</button>`;
    card.querySelector('button').onclick=()=>{pushHistory();l.locked=!l.locked;if(!l.locked)templateProtected=false;renderAll();syncBrandControls()};
    el.prepend(card);
  };
})();

/* ===== Inmo Studio PRO 2.5: etiqueta inteligente Lavinia ===== */
(function(){
  function smartLabelLayer(text='TIP',o={}){
    return layer('smartLabel',Object.assign({
      name:'Etiqueta inteligente',text:String(text||'TIP'),x:70,y:805,w:180,h:70,
      fill:'#ffffff',background:'#68c9c0',fontSize:27,fontFamily:'Avenir Next,Arial',
      fontWeight:900,align:'center',paddingX:30,paddingY:16,radius:36,lineHeight:1.15,
      maxWidth:820,uppercase:true,master:false,locked:false
    },o));
  }
  function smartLines(l){
    const raw=String(l.text||'TIP');
    const txt=l.uppercase===false?raw:raw.toUpperCase();
    const maxContent=Math.max(80,(Number(l.maxWidth)||820)-2*(Number(l.paddingX)||30));
    ctx.save();ctx.font=`${l.fontWeight||900} ${l.fontSize||27}px ${l.fontFamily||'Arial'}`;
    const result=[];
    txt.split('\n').forEach(par=>{
      const words=par.split(/\s+/).filter(Boolean);
      if(!words.length){result.push('');return}
      let line='';
      words.forEach(word=>{
        const test=line?line+' '+word:word;
        if(line&&ctx.measureText(test).width>maxContent){result.push(line);line=word}else line=test;
      });
      result.push(line);
    });
    ctx.restore();
    return result.length?result:['TIP'];
  }
  function sizeSmartLabel(l){
    const lines=smartLines(l),fs=Number(l.fontSize)||27,lh=fs*(Number(l.lineHeight)||1.15),px=Number(l.paddingX)||30,py=Number(l.paddingY)||16;
    ctx.save();ctx.font=`${l.fontWeight||900} ${fs}px ${l.fontFamily||'Arial'}`;
    const textW=Math.max(...lines.map(t=>ctx.measureText(t).width),60);ctx.restore();
    l.w=Math.min(Number(l.maxWidth)||820,Math.max(130,Math.ceil(textW+px*2)));
    l.h=Math.max(58,Math.ceil(lines.length*lh+py*2));
    l.radius=Math.min(Number(l.radius)||36,l.h/2);
    return {lines,fs,lh,px,py};
  }
  function convertSmartLabels(s){
    if(client!=='lavinia'||!s||!Array.isArray(s.layers))return s;
    let textIndex=s.layers.findIndex(l=>l.type==='text'&&(l.name==='Texto etiqueta'||['TIP','FRASE'].includes(String(l.text||'').toUpperCase())));
    if(textIndex<0)return s;
    const t=s.layers[textIndex];
    const shapeIndex=s.layers.findIndex(l=>l.name==='Fondo verde TIP');
    const x=shapeIndex>=0?s.layers[shapeIndex].x:(t.x||70)-12;
    const y=shapeIndex>=0?s.layers[shapeIndex].y:(t.y||818)-13;
    const smart=smartLabelLayer(t.text,{x,y,fontSize:t.fontSize||27,fill:t.fill||'#ffffff',fontFamily:t.fontFamily||'Avenir Next,Arial',fontWeight:t.fontWeight||900});
    const insertAt=Math.min(textIndex,shapeIndex>=0?shapeIndex:textIndex);
    s.layers=s.layers.filter((_,i)=>i!==textIndex&&i!==shapeIndex);
    s.layers.splice(insertAt,0,smart);sizeSmartLabel(smart);
    return s;
  }

  const priorTemplate25=template;
  template=function(name){return convertSmartLabels(priorTemplate25(name))};
  slidesData.forEach(convertSmartLabels);

  const priorDraw25=drawLayer;
  drawLayer=function(l){
    if(l.type!=='smartLabel')return priorDraw25(l);
    if(!l.visible)return;
    const m=sizeSmartLabel(l);
    ctx.save();ctx.globalAlpha=l.opacity??1;ctx.translate(l.x+l.w/2,l.y+l.h/2);ctx.rotate((l.rotation||0)*Math.PI/180);ctx.translate(-l.w/2,-l.h/2);
    ctx.fillStyle=l.background||'#68c9c0';roundRect(ctx,0,0,l.w,l.h,l.radius||0);ctx.fill();
    ctx.fillStyle=l.fill||'#ffffff';ctx.font=`${l.fontWeight||900} ${m.fs}px ${l.fontFamily||'Arial'}`;ctx.textBaseline='top';ctx.textAlign='center';
    m.lines.forEach((line,i)=>ctx.fillText(line,l.w/2,m.py+i*m.lh));ctx.restore();
  };

  function openSmartEditor(l){
    document.querySelector('.inline-text-editor,.inline-smart-label')?.remove();sizeSmartLabel(l);
    const ta=document.createElement('textarea');ta.className='inline-smart-label';ta.value=l.text||'';
    ta.style.left=l.x+'px';ta.style.top=l.y+'px';ta.style.width=l.w+'px';ta.style.height=l.h+'px';
    ta.style.fontFamily=l.fontFamily||'Arial';ta.style.fontSize=(l.fontSize||27)+'px';ta.style.fontWeight=l.fontWeight||900;ta.style.textAlign='center';
    ta.style.background=l.background||'#68c9c0';ta.style.color=l.fill||'#fff';ta.style.borderRadius=(l.radius||36)+'px';
    canvasShell.appendChild(ta);ta.focus();ta.select();let done=false;
    const refresh=()=>{l.text=ta.value;sizeSmartLabel(l);ta.style.width=l.w+'px';ta.style.height=l.h+'px';renderCanvas()};
    const commit=()=>{if(done)return;done=true;pushHistory();l.text=ta.value||'TIP';l.name='Etiqueta · '+(l.text.split('\n')[0]||'TIP').slice(0,18);sizeSmartLabel(l);ta.remove();renderAll()};
    ta.oninput=refresh;ta.onkeydown=e=>{if(e.key==='Escape'){e.preventDefault();ta.remove();renderAll()}if((e.ctrlKey||e.metaKey)&&e.key==='Enter'){e.preventDefault();commit()}};ta.onblur=commit;
  }
  const priorDbl25=canvas.ondblclick;
  canvas.ondblclick=e=>{const p=localPos(e),l=hit(p.x,p.y);if(l?.type==='smartLabel'){selected=l.id;openSmartEditor(l);return}priorDbl25?.(e)};

  const priorInspector25=renderInspector;
  renderInspector=function(){
    priorInspector25();const l=findLayer(selected),el=document.getElementById('inspector');if(!l||l.type!=='smartLabel'||!el)return;
    sizeSmartLabel(l);typeBadge.textContent='Etiqueta inteligente';
    const panel=document.createElement('div');panel.innerHTML=`
      <div class="smart-label-chip">▰ Texto + fondo unidos</div>
      <div class="field"><label>Texto</label><textarea id="smartText">${esc(l.text||'')}</textarea></div>
      <div class="smart-label-help">El fondo cambia de ancho y alto automáticamente. Enter crea otra línea.</div>
      <div class="smart-label-grid">
        <div class="field"><label>Fondo</label><input id="smartBg" type="color" value="${l.background||'#68c9c0'}"></div>
        <div class="field"><label>Texto</label><input id="smartColor" type="color" value="${l.fill||'#ffffff'}"></div>
        <div class="field"><label>Tamaño</label><input id="smartSize" type="number" min="12" max="100" value="${l.fontSize||27}"></div>
        <div class="field"><label>Ancho máximo</label><input id="smartMax" type="number" min="160" max="980" value="${l.maxWidth||820}"></div>
        <div class="field"><label>Espacio horizontal</label><input id="smartPX" type="number" min="4" max="100" value="${l.paddingX||30}"></div>
        <div class="field"><label>Espacio vertical</label><input id="smartPY" type="number" min="4" max="80" value="${l.paddingY||16}"></div>
        <div class="field"><label>Redondeado</label><input id="smartRadius" type="number" min="0" max="100" value="${l.radius||36}"></div>
        <div class="field"><label>Mayúsculas</label><select id="smartUpper"><option value="1" ${l.uppercase!==false?'selected':''}>Sí</option><option value="0" ${l.uppercase===false?'selected':''}>No</option></select></div>
      </div>`;
    el.insertBefore(panel,el.firstChild);
    const bind=(id,key,number=false)=>{const n=panel.querySelector('#'+id);let started=false;n.oninput=()=>{if(!started){pushHistory();started=true}l[key]=number?Number(n.value):n.value;sizeSmartLabel(l);renderCanvas();renderLayers()};n.onchange=()=>{started=false;renderInspector()}};
    bind('smartText','text');bind('smartBg','background');bind('smartColor','fill');bind('smartSize','fontSize',true);bind('smartMax','maxWidth',true);bind('smartPX','paddingX',true);bind('smartPY','paddingY',true);bind('smartRadius','radius',true);
    panel.querySelector('#smartUpper').onchange=e=>{pushHistory();l.uppercase=e.target.value==='1';sizeSmartLabel(l);renderAll()};
  };

  const priorAdd25=add;
  add=function(type){
    if(type!=='smartlabel')return priorAdd25(type);
    pushHistory();const l=smartLabelLayer('TIP',{x:90,y:180});sizeSmartLabel(l);current().layers.push(l);selected=l.id;renderAll();
  };

  const priorSetClient25=setClient;
  setClient=function(c){priorSetClient25(c);slidesData.forEach(convertSmartLabels);renderAll()};
  const priorNewDoc25=newDoc;
  newDoc=function(){priorNewDoc25();slidesData.forEach(convertSmartLabels);renderAll()};

  if(client==='lavinia'&&slidesData.length){slidesData.forEach(convertSmartLabels);renderAll()}
})();

/* v2.6 · Candado individual profesional para todas las capas */
(()=>{
  const iconForLayer=l=>l.type==='image'?'▧':l.type==='text'?'T':l.type==='smartLabel'?'▰':l.type==='logo'?'L':l.type==='shape'?'■':l.type==='ornament'?'◇':l.type==='gradient'?'◒':'•';
  const canChangeLocked=l=>!(l.master&&templateProtected&&l.locked);
  const toggleLayerLock=l=>{
    if(!l)return;
    if(l.master&&templateProtected&&l.locked){toast('Abre “Editar base” o desactiva “Proteger plantilla”');return}
    pushHistory();l.locked=!l.locked;renderAll();
    toast(l.locked?'Capa bloqueada':'Capa desbloqueada');
  };

  renderLayers=function(){
    layers.innerHTML='';
    [...current().layers].reverse().forEach(l=>{
      const r=document.createElement('div');
      r.className='layer-row'+(l.id===selected?' active':'')+(l.master?' master':'')+(l.locked?' is-locked':'');
      r.draggable=!l.locked;r.dataset.id=l.id;
      r.innerHTML=`
        <button class="eye" title="${l.visible?'Ocultar':'Mostrar'} capa">${l.visible?'◉':'○'}</button>
        <div class="layer-name" title="${esc(l.name)}"><span class="layer-type-icon">${iconForLayer(l)}</span> ${esc(l.name)}</div>
        ${l.master?'<span class="master-tag">MASTER</span>':'<span></span>'}
        <div class="layer-actions">
          <button class="layer-mini up" title="Subir capa">↑</button>
          <button class="layer-mini down" title="Bajar capa">↓</button>
          <button class="layer-mini duplicate-layer" title="Duplicar capa">⧉</button>
          <button class="layer-mini remove" title="Eliminar capa">×</button>
          <button class="layer-lock-btn ${l.locked?'locked':'unlocked'}" title="${l.locked?'Desbloquear capa':'Bloquear capa'}">${l.locked?'🔒':'🔓'}</button>
        </div>`;
      r.onclick=e=>{
        const t=e.target;
        if(t.closest('.eye')){pushHistory();l.visible=!l.visible;renderAll();return}
        if(t.closest('.layer-lock-btn')){toggleLayerLock(l);return}
        if(t.closest('.remove')){
          if(l.locked){toast('Desbloquea la capa para eliminarla');return}
          selected=l.id;act('delete');return
        }
        if(t.closest('.duplicate-layer')){selected=l.id;act('duplicate');return}
        if(t.closest('.up')){if(l.locked){toast('Desbloquea la capa para cambiar su orden');return}selected=l.id;act('front');return}
        if(t.closest('.down')){if(l.locked){toast('Desbloquea la capa para cambiar su orden');return}selected=l.id;act('back');return}
        selected=l.id;renderAll();
      };
      r.ondragstart=e=>{if(l.locked){e.preventDefault();return}r.classList.add('dragging')};
      r.ondragend=()=>r.classList.remove('dragging');
      r.ondragover=e=>{if(l.locked)return;e.preventDefault();r.classList.add('drag-over')};
      r.ondragleave=()=>r.classList.remove('drag-over');
      r.ondrop=e=>{
        e.preventDefault();r.classList.remove('drag-over');
        const fromRow=document.querySelector('.layer-row.dragging'),fromId=fromRow?.dataset.id,fromLayer=findLayer(fromId);
        if(!fromId||fromId===l.id||l.locked||fromLayer?.locked)return;
        pushHistory();const arr=current().layers,from=arr.findIndex(x=>x.id===fromId),to=arr.findIndex(x=>x.id===l.id);const [m]=arr.splice(from,1);arr.splice(to,0,m);renderAll();
      };
      layers.appendChild(r);
    });
  };

  const inspectorBeforeLock=renderInspector;
  renderInspector=function(){
    inspectorBeforeLock();
    const l=findLayer(selected),el=document.getElementById('inspector');if(!l||!el)return;
    const panel=document.createElement('div');panel.className='layer-lock-panel'+(l.locked?' locked':'');
    panel.innerHTML=`<div><b>${l.locked?'🔒 Capa bloqueada':'🔓 Capa editable'}</b><small>${l.locked?'No se puede mover, editar ni eliminar.':'Puedes moverla, redimensionarla y editarla.'}</small></div><button class="layer-lock-toggle">${l.locked?'Desbloquear':'Bloquear'}</button>`;
    panel.querySelector('button').onclick=()=>toggleLayerLock(l);
    el.insertBefore(panel,el.firstChild);
    if(l.locked){
      const note=document.createElement('div');note.className='inspector-locked-note';note.textContent='Desbloquea esta capa para modificar sus propiedades.';panel.after(note);
      [...el.querySelectorAll('input,textarea,select,[data-act]')].forEach(n=>{if(!n.closest('.layer-lock-panel'))n.disabled=true});
    }
  };

  const dblBeforeLock=canvas.ondblclick;
  canvas.ondblclick=e=>{
    const p=localPos(e),l=hit(p.x,p.y);
    if(l?.locked){selected=l.id;renderAll();toast('Desbloquea la capa para editarla');return}
    dblBeforeLock?.(e);
  };

  window.addEventListener('keydown',e=>{
    const tag=document.activeElement?.tagName;
    if(['INPUT','TEXTAREA','SELECT'].includes(tag))return;
    const l=findLayer(selected);
    if((e.ctrlKey||e.metaKey)&&e.key.toLowerCase()==='l'&&l){e.preventDefault();e.stopImmediatePropagation();toggleLayerLock(l);return}
    if(e.key==='Delete'&&l?.locked){e.preventDefault();e.stopImmediatePropagation();toast('Desbloquea la capa para eliminarla')}
  },true);

  renderAll();
})();

/* v3.2 · Reencuadre real: marco fijo + zoom y desplazamiento interno */
(()=>{
  let imageEditId=null;
  let contentDrag=null;
  let wheelHistoryReady=true;

  const selectedImage=()=>{const l=findLayer(selected);return l&&l.type==='image'?l:null};
  const ensureCrop=l=>{
    if(!l||l.type!=='image')return l;
    if(!Number.isFinite(+l.imageScale))l.imageScale=1;
    if(!Number.isFinite(+l.imageX))l.imageX=0;
    if(!Number.isFinite(+l.imageY))l.imageY=0;
    l.imageScale=Math.max(1,Math.min(8,+l.imageScale||1));
    if(!l.fit)l.fit='cover';
    return l;
  };
  const metrics=l=>{
    ensureCrop(l);const im=l.image?getImg(l.image):null;
    if(!im||!im.complete||!im.naturalWidth)return null;
    const base=Math.max(l.w/im.naturalWidth,l.h/im.naturalHeight);
    const ratio=base*l.imageScale;
    return {im,dw:im.naturalWidth*ratio,dh:im.naturalHeight*ratio};
  };
  const clamp=l=>{
    const m=metrics(l);if(!m)return;
    const maxX=Math.max(0,(m.dw-l.w)/2),maxY=Math.max(0,(m.dh-l.h)/2);
    l.imageX=Math.max(-maxX,Math.min(maxX,+l.imageX||0));
    l.imageY=Math.max(-maxY,Math.min(maxY,+l.imageY||0));
  };
  const setMode=(l,on)=>{
    if(on){
      if(!l||l.type!=='image')return;
      if(l.locked){toast('Desbloquea la capa para mover la foto');return}
      if(!l.image){selected=l.id;imageUpload.click();return}
      ensureCrop(l);imageEditId=l.id;selected=l.id;
      toast('MOVER FOTO activo: arrastra la fotografía y usa la rueda para zoom');
    }else{
      imageEditId=null;contentDrag=null;toast('MOVER MARCO activo');
    }
    renderAll();renderImageToolbar();
  };
  const reset=l=>{if(!l)return;pushHistory();l.imageScale=1;l.imageX=0;l.imageY=0;l.fit='cover';renderAll();renderImageToolbar()};
  const zoomImage=(l,next,anchor=null)=>{
    ensureCrop(l);const old=l.imageScale;
    const value=Math.max(1,Math.min(8,next));
    if(value===old)return;
    // Mantiene visualmente el punto bajo el cursor al hacer zoom.
    if(anchor){
      const cx=l.x+l.w/2,cy=l.y+l.h/2;
      const localX=anchor.x-cx,localY=anchor.y-cy;
      const ratio=value/old;
      l.imageX=(+l.imageX||0)-localX*(ratio-1);
      l.imageY=(+l.imageY||0)-localY*(ratio-1);
    }
    l.imageScale=value;clamp(l);
  };

  const drawBase=drawLayer;
  drawLayer=function(l){
    if(l.type!=='image')return drawBase(l);
    if(!l.visible)return;
    ctx.save();ctx.globalAlpha=l.opacity??1;
    ctx.translate(l.x+l.w/2,l.y+l.h/2);ctx.rotate((l.rotation||0)*Math.PI/180);ctx.translate(-l.w/2,-l.h/2);
    if(!l.image){placeholder(l);ctx.restore();return}
    const m=metrics(l);if(!m){placeholder(l);ctx.restore();return}
    clamp(l);
    ctx.save();roundRect(ctx,0,0,l.w,l.h,l.radius||0);ctx.clip();
    const dx=(l.w-m.dw)/2+(+l.imageX||0),dy=(l.h-m.dh)/2+(+l.imageY||0);
    ctx.drawImage(m.im,dx,dy,m.dw,m.dh);ctx.restore();ctx.restore();
  };

  const selBase=drawSelection;
  drawSelection=function(l){
    selBase(l);
    if(l.type==='image'&&imageEditId===l.id){
      ctx.save();ctx.strokeStyle='#20a37a';ctx.lineWidth=8/zoom;ctx.setLineDash([20/zoom,10/zoom]);ctx.strokeRect(l.x,l.y,l.w,l.h);ctx.setLineDash([]);
      const label=`MOVER FOTO · ${Math.round((l.imageScale||1)*100)}%`;ctx.font=`800 ${20/zoom}px Inter,Arial`;const tw=ctx.measureText(label).width;
      ctx.fillStyle='#20a37a';ctx.fillRect(l.x,l.y-36/zoom,tw+24/zoom,36/zoom);ctx.fillStyle='#fff';ctx.textBaseline='middle';ctx.fillText(label,l.x+12/zoom,l.y-18/zoom);ctx.restore();
    }
  };

  // Barra visible y permanente cuando una fotografía está seleccionada.
  const canvasbar=document.querySelector('.canvasbar');
  const workspaceEl=document.querySelector('.workspace');
  let cropbar=document.getElementById('imageModeBar');
  if(!cropbar){
    cropbar=document.createElement('div');cropbar.id='imageModeBar';cropbar.className='image-quickbar image-mode-static hidden';
    cropbar.innerHTML=`<div class="image-quick-title"><b>IMAGEN</b><small>Marco y encuadre</small></div><div class="image-mode-switch"><button type="button" data-mode="frame">▣ MOVER MARCO</button><button type="button" data-mode="photo">✥ MOVER FOTO</button></div><div class="image-zoom-tools"><button type="button" data-crop="minus" title="Alejar fotografía">−</button><input data-crop="zoom" type="range" min="100" max="800" value="100"><span data-crop="value">100%</span><button type="button" data-crop="plus" title="Acercar fotografía">+</button><button type="button" data-crop="reset" title="Restablecer encuadre">⌂</button></div>`;
    (workspaceEl||canvasbar)?.appendChild(cropbar);
  }
  window.INMO_STUDIO_VERSION='3.4.0';
  function renderImageToolbar(){
    const l=selectedImage();if(!l){cropbar.classList.add('hidden');cropbar.setAttribute('aria-hidden','true');return}
    cropbar.setAttribute('aria-hidden','false')
    ensureCrop(l);cropbar.classList.remove('hidden');
    cropbar.querySelector('[data-mode="frame"]').classList.toggle('active',imageEditId!==l.id);
    cropbar.querySelector('[data-mode="photo"]').classList.toggle('active',imageEditId===l.id);
    const z=cropbar.querySelector('[data-crop="zoom"]');z.value=Math.round(l.imageScale*100);
    cropbar.querySelector('[data-crop="value"]').textContent=`${Math.round(l.imageScale*100)}%`;
    cropbar.querySelectorAll('button,input').forEach(n=>n.disabled=!!l.locked);
  }
  cropbar.onclick=e=>{
    const l=selectedImage();if(!l)return;
    const target=e.target.closest('[data-mode],[data-crop]');if(!target)return;const mode=target.dataset.mode,act=target.dataset.crop;
    if(mode==='frame')setMode(l,false);
    if(mode==='photo')setMode(l,true);
    if(act==='minus'){pushHistory();zoomImage(l,l.imageScale/1.12);renderAll();renderImageToolbar()}
    if(act==='plus'){pushHistory();zoomImage(l,l.imageScale*1.12);renderAll();renderImageToolbar()}
    if(act==='reset')reset(l);
  };
  cropbar.querySelector('[data-crop="zoom"]').oninput=e=>{
    const l=selectedImage();if(!l||l.locked)return;
    zoomImage(l,+e.target.value/100);renderCanvas();renderInspector();renderImageToolbar();
  };
  cropbar.querySelector('[data-crop="zoom"]').onpointerdown=()=>pushHistory();

  canvas.onpointerdown=e=>{
    const p=localPos(e),l=hit(p.x,p.y);
    // Alt+arrastrar sobre una foto activa inmediatamente el movimiento interno.
    if(l?.type==='image'&&e.altKey&&imageEditId!==l.id)setMode(l,true);
    if(imageEditId){
      const active=findLayer(imageEditId);
      if(!active||active.locked){setMode(active,false);return}
      if(!l||l.id!==active.id){setMode(active,false);selected=l?.id||null;renderAll();renderImageToolbar();return}
      pushHistory();contentDrag={start:p,x:+active.imageX||0,y:+active.imageY||0};canvas.setPointerCapture(e.pointerId);canvas.style.cursor='grabbing';return;
    }
    if(!l){selected=null;renderAll();renderImageToolbar();return}
    selected=l.id;renderAll();renderImageToolbar();if(l.locked)return;
    pushHistory();let mode='move',corner='';for(const [i,h] of handles(l).entries())if(Math.hypot(p.x-h[0],p.y-h[1])<25){mode='resize';corner=i}
    drag={mode,corner,start:p,orig:deep(l)};canvas.setPointerCapture(e.pointerId);
  };
  canvas.onpointermove=e=>{
    if(contentDrag&&imageEditId){
      const p=localPos(e),l=findLayer(imageEditId);if(!l)return;
      l.imageX=Math.round(contentDrag.x+p.x-contentDrag.start.x);
      l.imageY=Math.round(contentDrag.y+p.y-contentDrag.start.y);
      clamp(l);renderCanvas();renderImageToolbar();return;
    }
    if(!drag)return;const p=localPos(e),l=findLayer(selected),dx=p.x-drag.start.x,dy=p.y-drag.start.y,o=drag.orig;
    if(drag.mode==='move'){l.x=Math.round(o.x+dx);l.y=Math.round(o.y+dy)}else{
      if(drag.corner==0){l.x=o.x+dx;l.y=o.y+dy;l.w=o.w-dx;l.h=o.h-dy}if(drag.corner==1){l.y=o.y+dy;l.w=o.w+dx;l.h=o.h-dy}if(drag.corner==2){l.x=o.x+dx;l.w=o.w-dx;l.h=o.h+dy}if(drag.corner==3){l.w=o.w+dx;l.h=o.h+dy}
      l.w=Math.max(40,l.w);l.h=Math.max(30,l.h);if(l.type==='image')clamp(l)
    }renderCanvas();renderLayers();
  };
  canvas.onpointerup=()=>{contentDrag=null;drag=null;canvas.style.cursor='';renderInspector();renderImageToolbar()};
  canvas.onpointercancel=()=>{contentDrag=null;drag=null;canvas.style.cursor=''};

  canvas.addEventListener('wheel',e=>{
    const p=localPos(e),under=hit(p.x,p.y),l=imageEditId?findLayer(imageEditId):null;
    if(!l||under?.id!==l.id||l.locked)return;
    e.preventDefault();
    if(wheelHistoryReady){pushHistory();wheelHistoryReady=false;setTimeout(()=>wheelHistoryReady=true,350)}
    zoomImage(l,l.imageScale*(e.deltaY<0?1.09:.92),p);renderCanvas();renderInspector();renderImageToolbar();
  },{passive:false});

  const dblBase=canvas.ondblclick;
  canvas.ondblclick=e=>{
    const p=localPos(e),l=hit(p.x,p.y);
    if(l?.type==='image'){
      e.preventDefault();e.stopPropagation();selected=l.id;
      setMode(l,imageEditId!==l.id);return;
    }
    if(imageEditId)setMode(findLayer(imageEditId),false);dblBase?.(e);
  };

  const inspectorBase=renderInspector;
  renderInspector=function(){
    inspectorBase();const l=selectedImage(),el=document.getElementById('inspector');renderImageToolbar();if(!l||!el)return;
    ensureCrop(l);const editing=imageEditId===l.id;
    const panel=document.createElement('section');panel.className='image-crop-panel'+(editing?' editing':'');
    panel.innerHTML=`
      <div class="image-crop-head"><div><b>Marco y fotografía</b><small>${editing?'Estás moviendo la FOTO dentro del marco.':'Estás moviendo el MARCO completo.'}</small></div><span>${editing?'MODO FOTO':'MODO MARCO'}</span></div>
      <div class="image-mode-big">
        <button data-img-mode="frame" class="${editing?'':'active'}">▣<b>Mover marco</b><small>Mueve o redimensiona el bloque</small></button>
        <button data-img-mode="photo" class="${editing?'active':''}">✥<b>Mover foto</b><small>Zoom y posición dentro del bloque</small></button>
      </div>
      <div class="image-crop-actions"><button data-img-act="replace">↻ Reemplazar</button><button data-img-act="reset">⌂ Restablecer</button></div>
      <div class="field"><label>Zoom interno <span>${Math.round(l.imageScale*100)}%</span></label><input id="imageCropZoom" type="range" min="100" max="800" value="${Math.round(l.imageScale*100)}"></div>
      <div class="image-nudge"><button data-nudge="left">←</button><button data-nudge="up">↑</button><button data-nudge="down">↓</button><button data-nudge="right">→</button></div>
      <div class="row2"><div class="field"><label>Desplazamiento X</label><input id="imageCropX" type="number" value="${Math.round(l.imageX||0)}"></div><div class="field"><label>Desplazamiento Y</label><input id="imageCropY" type="number" value="${Math.round(l.imageY||0)}"></div></div>
      <div class="image-crop-hint"><b>Uso rápido:</b> doble clic → arrastrar la foto → rueda para zoom. También puedes usar Alt + arrastrar.</div>`;
    el.insertBefore(panel,el.firstChild);
    panel.querySelector('[data-img-mode="frame"]').onclick=()=>setMode(l,false);
    panel.querySelector('[data-img-mode="photo"]').onclick=()=>setMode(l,true);
    panel.querySelector('[data-img-act="replace"]').onclick=()=>{selected=l.id;imageUpload.click()};
    panel.querySelector('[data-img-act="reset"]').onclick=()=>reset(l);
    panel.querySelectorAll('[data-nudge]').forEach(b=>b.onclick=()=>{pushHistory();const step=12;if(b.dataset.nudge==='left')l.imageX-=step;if(b.dataset.nudge==='right')l.imageX+=step;if(b.dataset.nudge==='up')l.imageY-=step;if(b.dataset.nudge==='down')l.imageY+=step;clamp(l);renderAll();renderImageToolbar()});
    let started=false;const update=(key,value)=>{if(!started){pushHistory();started=true}l[key]=+value;clamp(l);renderCanvas();renderLayers();renderImageToolbar()};
    const z=panel.querySelector('#imageCropZoom'),x=panel.querySelector('#imageCropX'),y=panel.querySelector('#imageCropY');
    z.oninput=()=>update('imageScale',+z.value/100);x.oninput=()=>update('imageX',x.value);y.oninput=()=>update('imageY',y.value);
    [z,x,y].forEach(n=>n.onchange=()=>{started=false;renderInspector()});
    if(l.locked)panel.querySelectorAll('button,input').forEach(n=>n.disabled=true);
  };

  const layersBase=renderLayers;
  renderLayers=function(){if(imageEditId&&!findLayer(imageEditId))imageEditId=null;layersBase();renderImageToolbar()};
  const actBase=act;
  act=function(a){if(a==='delete'&&selected===imageEditId)imageEditId=null;actBase(a);renderImageToolbar()};

  window.addEventListener('keydown',e=>{
    if(e.key==='Escape'&&imageEditId){e.preventDefault();e.stopImmediatePropagation();setMode(findLayer(imageEditId),false)}
    if(e.key==='Enter'&&imageEditId&&!['INPUT','TEXTAREA','SELECT'].includes(document.activeElement?.tagName)){e.preventDefault();setMode(findLayer(imageEditId),false)}
  },true);

  renderAll();renderImageToolbar();
})();
